sql:
SELECT COUNT(*) AS in_transit_shipments
FROM cargo_shipments
WHERE status = 'in transit';

SELECT category_name
FROM cargo_categories
WHERE is_reefer = 1;

SELECT category_name, is_reefer, unit_of_measurement
FROM cargo_categories
ORDER BY category_name ASC;

external_knowledge:
- 'In transit' and 'delivered' refer to the statuses of cargo shipments; 
- Vessel details include the vessel name, type, capacity, owner, and International Maritime Organization (IMO) number;
- Port and city of origin refer to the starting point of the shipment;
- Country of origin refers to the country where the shipment started;
- Current location refers to the latest known location of the shipment;
- Latest inspection results include the outcome and comments from the most recent inspection.

sql:
SELECT tracking_date
FROM cargo_tracking
WHERE status = 'in transit';

SELECT category_name
FROM cargo_categories
ORDER BY category_name ASC;

SELECT COUNT(*) AS defect_count
FROM cargo_inspection
WHERE defect_found = 1;

SELECT COUNT(*) AS total_in_transit_shipments
FROM cargo_tracking
WHERE status = 'en route' AND tracking_date = '2023-09-02';

SELECT inspection_date, inspection_result
FROM cargo_inspection
ORDER BY inspection_date DESC;
